import type { RequestHandler } from 'express'

export function buildProxyHandler(target: ServiceName): RequestHandler {
  return async (req, res, next) => {
    const upstream = serviceUrl(target) + req.originalUrl
    const response = await fetch(upstream, {
      method: req.method,
      headers: forwardHeaders(req),
      body: req.method === 'GET' ? undefined : req
    })
    relayResponse(response, res)
    next()
  }
}

import type { RequestHandler } from 'express'

// trust x-gateway-sub only from trusted internal gateway
export const authz: RequestHandler = (req, res, next) => {
  const subject = req.header('x-gateway-sub') ?? req.header('x-user-id')
  if (!subject) return res.status(401).json({ error: 'missing subject' })
  req.context = { ...req.context, subject }
  next()
}
